<script setup lang="ts">
definePageMeta({ layout: 'default', alias: ['/simulation'] })
const form = reactive({ product: 'orchestrator', domain: 'infra', actionType: 'improvement:ship', intent: '', reversibility: 'reversible', blastRadius: 'small', affectedUsers: 0, affectedApps: 1, expectedRevenueUsd: 0, expectedErrorReductionPct: 0, expectedUxLiftPct: 0, estimatedCostUsd: 0, confidence: .7, ifNotDone: '' })
const result = ref<any>(null), loading = ref(false), error = ref('')
async function simulate() { if (!form.intent.trim()) return; loading.value = true; error.value = ''; try { result.value = await $fetch('/api/fleet/guidance', { method: 'POST', body: { ...form, evidence: [{ source: 'operator estimate', confidence: form.confidence }] } }) } catch (e: any) { error.value = e?.data?.message || e?.message } finally { loading.value = false } }
</script>
<template><div class="min-h-full bg-gray-50"><header class="border-b bg-white px-6 py-5"><div class="text-[10px] font-semibold uppercase tracking-[.16em] text-blue-600">AI decision intelligence</div><h1 class="mt-1 text-2xl font-semibold">Portfolio digital twin</h1><p class="mt-2 text-sm text-gray-500">Model an improvement, policy, connector, deployment, or operator action before committing it.</p></header><main class="mx-auto grid max-w-6xl gap-6 p-6 lg:grid-cols-[22rem_minmax(0,1fr)]"><form class="space-y-3 rounded-xl border bg-white p-4" @submit.prevent="simulate"><label class="block text-xs font-medium">Intent<textarea v-model="form.intent" required rows="3" class="mt-1 w-full rounded-lg border p-2" placeholder="Describe exactly what will change"></textarea></label><div class="grid grid-cols-2 gap-2"><label class="text-xs font-medium">Product<input v-model="form.product" class="mt-1 w-full rounded-lg border p-2"></label><label class="text-xs font-medium">Domain<select v-model="form.domain" class="mt-1 w-full rounded-lg border p-2"><option>infra</option><option>users_access</option><option>billing</option><option>trust_safety</option></select></label><label class="text-xs font-medium">Reversibility<select v-model="form.reversibility" class="mt-1 w-full rounded-lg border p-2"><option>reversible</option><option>hard_to_reverse</option><option>irreversible</option></select></label><label class="text-xs font-medium">Blast radius<select v-model="form.blastRadius" class="mt-1 w-full rounded-lg border p-2"><option>single</option><option>small</option><option>large</option><option>fleet</option></select></label><label class="text-xs font-medium">Affected users<input v-model.number="form.affectedUsers" type="number" min="0" class="mt-1 w-full rounded-lg border p-2"></label><label class="text-xs font-medium">Affected apps<input v-model.number="form.affectedApps" type="number" min="0" class="mt-1 w-full rounded-lg border p-2"></label><label class="text-xs font-medium">Revenue upside ($)<input v-model.number="form.expectedRevenueUsd" type="number" min="0" class="mt-1 w-full rounded-lg border p-2"></label><label class="text-xs font-medium">Estimated cost ($)<input v-model.number="form.estimatedCostUsd" type="number" min="0" class="mt-1 w-full rounded-lg border p-2"></label><label class="text-xs font-medium">Error reduction %<input v-model.number="form.expectedErrorReductionPct" type="number" min="0" max="100" class="mt-1 w-full rounded-lg border p-2"></label><label class="text-xs font-medium">UX lift %<input v-model.number="form.expectedUxLiftPct" type="number" min="0" max="100" class="mt-1 w-full rounded-lg border p-2"></label></div><label class="block text-xs font-medium">If nothing changes<input v-model="form.ifNotDone" class="mt-1 w-full rounded-lg border p-2"></label><button :disabled="loading" class="w-full rounded-lg bg-gray-900 px-4 py-2.5 text-xs font-medium text-white">{{ loading ? 'Simulating…' : 'Simulate before action' }}</button></form><section><div v-if="error" class="rounded-xl border border-red-200 bg-red-50 p-5 text-sm text-red-700">{{ error }}</div><div v-else-if="!result" class="rounded-xl border border-dashed bg-white p-10 text-center"><div class="text-sm font-medium">No simulation yet</div><p class="mt-2 text-xs text-gray-500">Define an action to compare expected value, success, risk, blast, alternatives, and evidence gaps.</p></div><div v-else class="space-y-4"><div class="rounded-xl border bg-white p-5"><div class="text-xs font-semibold uppercase text-blue-600">{{ result.recommendation.replaceAll('_',' ') }}</div><h2 class="mt-1 text-lg font-semibold">{{ result.summary }}</h2><div class="mt-4 grid grid-cols-2 gap-3 sm:grid-cols-4"><div v-for="m in [{l:'Value',v:result.expectedValue+'/100'},{l:'Success',v:Math.round(result.successProbability*100)+'%'},{l:'Risk',v:result.riskScore+'/100'},{l:'Confidence',v:Math.round(result.confidence*100)+'%'}]" :key="m.l" class="rounded-lg bg-gray-50 p-3"><div class="text-[10px] text-gray-400">{{m.l}}</div><div class="text-lg font-semibold">{{m.v}}</div></div></div></div><div class="grid gap-4 md:grid-cols-2"><article v-for="block in [{t:'Guardrails',x:result.guardrails},{t:'Alternatives',x:result.alternatives},{t:'Evidence gaps',x:result.missingEvidence},{t:'Proof requirements',x:result.proofRequirements}]" :key="block.t" class="rounded-xl border bg-white p-4"><h3 class="text-sm font-semibold">{{block.t}}</h3><ul class="mt-2 list-disc space-y-1 pl-4 text-xs text-gray-600"><li v-for="x in block.x" :key="x">{{x}}</li></ul></article></div></div></section></main></div></template>
